from dataclasses import dataclass, field
from typing import Callable
import hashlib, math, random

@dataclass
class WatermarkConfig:
    enabled: bool = True
    secret_key: bytes = b"change-me-in-production"
    delta: float = 2.0          # logit bias for green tokens
    gamma: float = 0.5          # fraction of vocab on the green list
    h: int = 4                  # context window for green-list hash
    z_threshold: float = 4.0    # detection threshold
    min_tokens_for_detection: int = 100

class WatermarkDecoder:
    """
    Wraps a logit-sampling function to apply KGW watermarking.
    Usage:
        decoder = WatermarkDecoder(config)
        next_token = decoder.sample(logits, context_ids)
    """
    def __init__(self, config: WatermarkConfig):
        self.cfg = config

    def _green_list(self, context_ids: list[int], vocab_size: int) -> set[int]:
        seed_bytes = self.cfg.secret_key + b"|" + b",".join(
            str(t).encode() for t in context_ids[-self.cfg.h:]
        )
        digest = hashlib.sha256(seed_bytes).hexdigest()
        rng = random.Random(int(digest, 16) % (2 ** 32))
        all_ids = list(range(vocab_size))
        rng.shuffle(all_ids)
        return set(all_ids[:int(vocab_size * self.cfg.gamma)])

    def apply_bias(self, logits: list[float], context_ids: list[int]) -> list[float]:
        if not self.cfg.enabled:
            return logits
        green = self._green_list(context_ids, len(logits))
        return [l + self.cfg.delta if i in green else l for i, l in enumerate(logits)]

    def is_green(self, token_id: int, context_ids: list[int], vocab_size: int) -> bool:
        return token_id in self._green_list(context_ids, vocab_size)


class WatermarkDetector:
    """Stateless detector — only needs the config (no original prompt)."""
    def __init__(self, config: WatermarkConfig):
        self.cfg = config
        self._decoder = WatermarkDecoder(config)

    def score(self, token_ids: list[int], vocab_size: int) -> dict:
        green_count = 0
        effective = 0
        for i in range(self.cfg.h, len(token_ids)):
            ctx = token_ids[i - self.cfg.h : i]
            if self._decoder.is_green(token_ids[i], ctx, vocab_size):
                green_count += 1
            effective += 1

        if effective < self.cfg.min_tokens_for_detection:
            return {"reliable": False, "reason": f"Need >= {self.cfg.min_tokens_for_detection} tokens"}

        gamma = self.cfg.gamma
        z = (green_count - effective * gamma) / math.sqrt(effective * gamma * (1 - gamma))
        p = 0.5 * math.erfc(z / math.sqrt(2))
        return {
            "reliable": True,
            "n_tokens": effective,
            "n_green": green_count,
            "z_score": round(z, 4),
            "p_value": round(p, 8),
            "is_watermarked": z > self.cfg.z_threshold,
        }
